// ManagerProfile.js - بروفيل المدير الكامل مع 6 مربعات
import React, { useState } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

export default function ManagerProfile() {
  // ==================== بيانات البروفيل ====================
  const [managerInfo, setManagerInfo] = useState({
    name: "Ahmed Benali",
    role: "Directeur du Restaurant",
    experience: "12 ans d'expérience",
    bio: "Passionné par la restauration depuis plus de 12 ans, je dirige ce magnifique établissement avec une équipe dévouée pour offrir la meilleure expérience culinaire à nos clients.",
    email: "ahmed.benali@andalus-restaurant.dz",
    phone: "+213 5 55 55 55 55",
    location: "Alger, Algérie",
    languages: ["Français", "Arabe", "Anglais"]
  });
  
  // ==================== STATE MANAGEMENT ====================
  
  // المربع 1: الطاولات
  const [tables, setTables] = useState([]);
  const [newTableCount, setNewTableCount] = useState(1);
  const [selectedGroupForTable, setSelectedGroupForTable] = useState("");
  const [showQRPlaceholder, setShowQRPlaceholder] = useState(false);
  const [selectedTableForQR, setSelectedTableForQR] = useState(null);
  
  // المربع 2: المجموعات
  const [groups, setGroups] = useState([
    { id: 1, name: "Groupe 1", tableIds: [], tableRange: { start: 1, end: 9 } }
  ]);
  const [newGroupName, setNewGroupName] = useState("");
  
  // المربع 3: الموظفين والربط
  const [employees, setEmployees] = useState([
    { id: 1, name: "Youssef", role: "Employé", groupId: 1, status: "active" },
    { id: 2, name: "Mohamed", role: "Employé", groupId: null, status: "active" }
  ]);
  const [newEmployeeName, setNewEmployeeName] = useState("");
  
  // المربع 4: المنيو
  const [menuCategories, setMenuCategories] = useState([
    { id: 1, name: "Chicha", icon: "💨", color: "#ff6b6b", products: [
      { id: 101, name: "Chicha Pomme", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 102, name: "Chicha Raisin", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 103, name: "Chicha Menthe", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" }
    ] },
    { id: 2, name: "Plats", icon: "🍔", color: "#4ecdc4", products: [
      { id: 201, name: "Burger", price: 12, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
      { id: 202, name: "Pizza", price: 18, image: "https://cdn-icons-png.flaticon.com/512/1046/1046796.png" }
    ] },
    { id: 3, name: "Boissons", icon: "🥤", color: "#45b7d1", products: [
      { id: 301, name: "Coca Cola", price: 3, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
      { id: 302, name: "Jus d'Orange", price: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" }
    ] },
    { id: 4, name: "Desserts", icon: "🍰", color: "#f9ca24", products: [
      { id: 401, name: "Gâteau", price: 7, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
      { id: 402, name: "Glace", price: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046800.png" }
    ] }
  ]);
  
  const [showAddProductModal, setShowAddProductModal] = useState(false);
  const [showDeleteProductModal, setShowDeleteProductModal] = useState(false);
  const [showEditPriceModal, setShowEditPriceModal] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [newProduct, setNewProduct] = useState({ name: "", price: 0, image: "" });
  const [productImagePreview, setProductImagePreview] = useState("");
  
  // المربع 5: كرت المطعم
  const [restaurantCard, setRestaurantCard] = useState({
    name: "Restaurant Andalous",
    location: "Alger, Algérie",
    description: "Les meilleurs plats arabes et internationaux dans une ambiance familiale",
    image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
    phone: "+213 5 55 55 55 55",
    email: "info@andalus-restaurant.dz"
  });
  const [showEditRestaurantModal, setShowEditRestaurantModal] = useState(false);
  const [tempRestaurantCard, setTempRestaurantCard] = useState({ ...restaurantCard });
  const [restaurantImagePreview, setRestaurantImagePreview] = useState("");
  
  // المربع 6: الفواتير
  const [invoices, setInvoices] = useState([]);
  const [groupInvoices, setGroupInvoices] = useState([]);
  const [restaurantInvoice, setRestaurantInvoice] = useState(null);
  const [filterType, setFilterType] = useState("daily");
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [selectedSeason, setSelectedSeason] = useState("spring");
  const [invoiceViewType, setInvoiceViewType] = useState("tables");
  const [showInvoices, setShowInvoices] = useState(false);
  
  // ==================== FUNCTIONS ====================
  
  // المربع 1: إدارة الطاولات
  const addTables = () => {
    const startId = tables.length + 1;
    const newTables = [];
    for (let i = 0; i < newTableCount; i++) {
      const tableId = startId + i;
      newTables.push({
        id: tableId,
        number: tableId,
        groupId: selectedGroupForTable || null,
        status: "free"
      });
    }
    setTables([...tables, ...newTables]);
    alert(`✅ ${newTableCount} nouvelle(s) table(s) ajoutée(s) avec succès!`);
  };
  
  const showQRPlaceholderFunc = (table) => {
    setSelectedTableForQR(table);
    setShowQRPlaceholder(true);
  };
  
  // المربع 2: إدارة المجموعات
  const addGroup = () => {
    if (!newGroupName.trim()) {
      alert("⚠️ Veuillez entrer un nom de groupe");
      return;
    }
    const newGroup = {
      id: groups.length + 1,
      name: newGroupName,
      tableIds: [],
      tableRange: { start: null, end: null }
    };
    setGroups([...groups, newGroup]);
    setNewGroupName("");
    alert(`✅ Groupe "${newGroupName}" ajouté avec succès`);
  };
  
  const checkOverlap = (startTable, endTable, currentGroupId = null) => {
    for (const group of groups) {
      if (currentGroupId !== null && group.id === currentGroupId) continue;
      if (group.tableRange.start && group.tableRange.end) {
        if (!(endTable < group.tableRange.start || startTable > group.tableRange.end)) {
          return `Conflit avec ${group.name} (tables ${group.tableRange.start} → ${group.tableRange.end})`;
        }
      }
    }
    return null;
  };
  
  const assignTablesToGroup = (groupId, startTable, endTable) => {
    if (startTable > endTable) {
      alert("⚠️ Le numéro de début doit être inférieur au numéro de fin");
      return;
    }
    
    const overlapError = checkOverlap(startTable, endTable, groupId);
    if (overlapError) {
      alert(`⚠️ Impossible d'assigner ces tables: ${overlapError}`);
      return;
    }
    
    const availableTables = [];
    for (let i = startTable; i <= endTable; i++) {
      const tableExists = tables.find(t => t.number === i);
      if (tableExists) {
        availableTables.push(i);
      }
    }
    
    if (availableTables.length === 0) {
      alert("⚠️ Aucune table dans cette plage. Ajoutez des tables d'abord.");
      return;
    }
    
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        return {
          ...group,
          tableIds: availableTables,
          tableRange: { start: startTable, end: endTable }
        };
      }
      return group;
    });
    setGroups(updatedGroups);
    
    const updatedTables = tables.map(table => {
      if (table.number >= startTable && table.number <= endTable) {
        return { ...table, groupId };
      }
      return table;
    });
    setTables(updatedTables);
    
    alert(`✅ Tables ${startTable} à ${endTable} assignées au groupe ${groupId}`);
  };
  
  // المربع 3: ربط الموظفين
  const addEmployee = () => {
    if (!newEmployeeName.trim()) {
      alert("⚠️ Veuillez entrer un nom d'employé");
      return;
    }
    const newEmployee = {
      id: employees.length + 1,
      name: newEmployeeName,
      role: "Employé",
      groupId: null,
      status: "active"
    };
    setEmployees([...employees, newEmployee]);
    setNewEmployeeName("");
    alert(`✅ Employé "${newEmployeeName}" ajouté avec succès`);
  };
  
  const assignEmployeeToGroup = (employeeId, groupId) => {
    const updatedEmployees = employees.map(emp => {
      if (emp.id === employeeId) {
        return { ...emp, groupId };
      }
      return emp;
    });
    setEmployees(updatedEmployees);
    
    const employee = employees.find(e => e.id === employeeId);
    const group = groups.find(g => g.id === groupId);
    alert(`✅ ${employee?.name} assigné au ${group?.name}`);
  };
  
  // المربع 4: تعديل المنيو
  const handleProductImageChange = (e) => {
    const url = e.target.value;
    setNewProduct({ ...newProduct, image: url });
    setProductImagePreview(url);
  };
  
  const addProduct = () => {
    if (!newProduct.name || newProduct.price <= 0) {
      alert("⚠️ Veuillez entrer un nom et un prix valide");
      return;
    }
    
    const defaultImage = "https://cdn-icons-png.flaticon.com/512/1046/1046784.png";
    
    const updatedCategories = menuCategories.map(cat => {
      if (cat.id === selectedCategory) {
        const newId = Math.max(...cat.products.map(p => p.id), 0) + 1;
        return {
          ...cat,
          products: [...cat.products, { 
            ...newProduct, 
            id: newId, 
            image: newProduct.image || defaultImage 
          }]
        };
      }
      return cat;
    });
    setMenuCategories(updatedCategories);
    setShowAddProductModal(false);
    setNewProduct({ name: "", price: 0, image: "" });
    setProductImagePreview("");
    alert(`✅ Produit "${newProduct.name}" ajouté avec succès`);
  };
  
  const deleteProduct = (categoryId, productId) => {
    const updatedCategories = menuCategories.map(cat => {
      if (cat.id === categoryId) {
        return {
          ...cat,
          products: cat.products.filter(p => p.id !== productId)
        };
      }
      return cat;
    });
    setMenuCategories(updatedCategories);
    alert(`✅ Produit supprimé avec succès`);
  };
  
  const updateProductPrice = (categoryId, productId, newPrice) => {
    const updatedCategories = menuCategories.map(cat => {
      if (cat.id === categoryId) {
        return {
          ...cat,
          products: cat.products.map(p => 
            p.id === productId ? { ...p, price: newPrice } : p
          )
        };
      }
      return cat;
    });
    setMenuCategories(updatedCategories);
    alert(`✅ Prix mis à jour avec succès`);
  };
  
  // المربع 5: كرت المطعم
  const handleRestaurantImageChange = (e) => {
    const url = e.target.value;
    setTempRestaurantCard({ ...tempRestaurantCard, image: url });
    setRestaurantImagePreview(url);
  };
  
  const handleRestaurantLogoChange = (e) => {
    const url = e.target.value;
    setTempRestaurantCard({ ...tempRestaurantCard, logo: url });
  };
  
  const updateRestaurantCard = () => {
    setRestaurantCard({ ...tempRestaurantCard });
    setShowEditRestaurantModal(false);
    setRestaurantImagePreview("");
    alert(`✅ Carte du restaurant mise à jour avec succès`);
  };
  
  // المربع 6: الفواتير
  const toggleInvoices = () => {
    if (!showInvoices) {
      generateInvoice();
    } else {
      setShowInvoices(false);
      setInvoices([]);
      setGroupInvoices([]);
      setRestaurantInvoice(null);
    }
  };
  
  const generateInvoice = () => {
    const mockInvoices = [];
    const mockGroupInvoices = [];
    
    if (filterType === "daily") {
      for (let i = 1; i <= 20; i++) {
        const groupId = i <= 9 ? 1 : (i <= 16 ? 2 : 3);
        mockInvoices.push({
          id: i,
          tableNumber: i,
          groupId: groupId,
          groupName: groups.find(g => g.id === groupId)?.name || `Groupe ${groupId}`,
          total: Math.floor(Math.random() * 500 + 100),
          items: Math.floor(Math.random() * 5 + 1),
          date: selectedDate,
          time: `${Math.floor(Math.random() * 12 + 10)}:${Math.floor(Math.random() * 60)}`
        });
      }
      
      const groupTotals = {};
      mockInvoices.forEach(inv => {
        if (!groupTotals[inv.groupId]) {
          groupTotals[inv.groupId] = {
            groupId: inv.groupId,
            groupName: inv.groupName,
            total: 0,
            tableCount: 0,
            orderCount: 0
          };
        }
        groupTotals[inv.groupId].total += inv.total;
        groupTotals[inv.groupId].tableCount++;
        groupTotals[inv.groupId].orderCount += inv.items;
      });
      mockGroupInvoices.push(...Object.values(groupTotals));
      
      const restaurantTotal = mockInvoices.reduce((sum, inv) => sum + inv.total, 0);
      setRestaurantInvoice({
        total: restaurantTotal,
        tableCount: mockInvoices.length,
        orderCount: mockInvoices.reduce((sum, inv) => sum + inv.items, 0),
        date: selectedDate
      });
      
    } else if (filterType === "monthly") {
      for (let i = 1; i <= 20; i++) {
        const groupId = i <= 9 ? 1 : (i <= 16 ? 2 : 3);
        for (let day = 1; day <= 30; day++) {
          if (Math.random() > 0.7) {
            mockInvoices.push({
              id: `${i}_${day}`,
              tableNumber: i,
              groupId: groupId,
              groupName: groups.find(g => g.id === groupId)?.name || `Groupe ${groupId}`,
              total: Math.floor(Math.random() * 500 + 100),
              items: Math.floor(Math.random() * 5 + 1),
              date: `${selectedYear}-${String(selectedMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`
            });
          }
        }
      }
      
      const groupTotals = {};
      mockInvoices.forEach(inv => {
        if (!groupTotals[inv.groupId]) {
          groupTotals[inv.groupId] = {
            groupId: inv.groupId,
            groupName: inv.groupName,
            total: 0,
            tableCount: 0,
            orderCount: 0
          };
        }
        groupTotals[inv.groupId].total += inv.total;
        groupTotals[inv.groupId].tableCount++;
        groupTotals[inv.groupId].orderCount += inv.items;
      });
      mockGroupInvoices.push(...Object.values(groupTotals));
      
      const restaurantTotal = mockInvoices.reduce((sum, inv) => sum + inv.total, 0);
      setRestaurantInvoice({
        total: restaurantTotal,
        tableCount: mockInvoices.length,
        orderCount: mockInvoices.reduce((sum, inv) => sum + inv.items, 0),
        month: selectedMonth + 1,
        year: selectedYear
      });
      
    } else {
      const months = selectedSeason === "spring" ? [2, 3, 4] : selectedSeason === "summer" ? [5, 6, 7] : selectedSeason === "autumn" ? [8, 9, 10] : [11, 0, 1];
      for (let i = 1; i <= 20; i++) {
        const groupId = i <= 9 ? 1 : (i <= 16 ? 2 : 3);
        for (let day = 1; day <= 90; day++) {
          if (Math.random() > 0.85) {
            mockInvoices.push({
              id: `${i}_${day}`,
              tableNumber: i,
              groupId: groupId,
              groupName: groups.find(g => g.id === groupId)?.name || `Groupe ${groupId}`,
              total: Math.floor(Math.random() * 500 + 100),
              items: Math.floor(Math.random() * 5 + 1),
              date: `${selectedYear}-${String(months[Math.floor(Math.random() * months.length)] + 1).padStart(2, '0')}-${String(Math.floor(Math.random() * 28) + 1).padStart(2, '0')}`
            });
          }
        }
      }
      
      const groupTotals = {};
      mockInvoices.forEach(inv => {
        if (!groupTotals[inv.groupId]) {
          groupTotals[inv.groupId] = {
            groupId: inv.groupId,
            groupName: inv.groupName,
            total: 0,
            tableCount: 0,
            orderCount: 0
          };
        }
        groupTotals[inv.groupId].total += inv.total;
        groupTotals[inv.groupId].tableCount++;
        groupTotals[inv.groupId].orderCount += inv.items;
      });
      mockGroupInvoices.push(...Object.values(groupTotals));
      
      const restaurantTotal = mockInvoices.reduce((sum, inv) => sum + inv.total, 0);
      setRestaurantInvoice({
        total: restaurantTotal,
        tableCount: mockInvoices.length,
        orderCount: mockInvoices.reduce((sum, inv) => sum + inv.items, 0),
        season: selectedSeason === "spring" ? "Printemps" : selectedSeason === "summer" ? "Été" : selectedSeason === "autumn" ? "Automne" : "Hiver",
        year: selectedYear
      });
    }
    
    setInvoices(mockInvoices);
    setGroupInvoices(mockGroupInvoices);
    setShowInvoices(true);
  };
  
  const getTotalRevenue = () => {
    return invoices.reduce((sum, inv) => sum + inv.total, 0);
  };
  
  // ==================== STYLES ====================
  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes shoot {
      0% { transform: translateX(0) translateY(0) rotate(45deg); opacity: 0; }
      5% { opacity: 1; }
      95% { opacity: 1; }
      100% { transform: translateX(-300px) translateY(300px) rotate(45deg); opacity: 0; }
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    @keyframes gradient-border {
      0% { background-position: 0% 0%; }
      50% { background-position: 400% 0%; }
      100% { background-position: 0% 0%; }
    }
    
    @keyframes borderPulse {
      0%, 100% { opacity: 0.6; filter: blur(8px); }
      50% { opacity: 1; filter: blur(12px); }
    }
    
    @keyframes rainbowLine {
      0% { background-position: 0% 50%; }
      100% { background-position: 200% 50%; }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
      padding-top: 80px;
    }
    
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .shooting-star {
      position: absolute;
      width: 2px;
      height: 2px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,255,0) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2s ease-out infinite;
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    .gradient-border-box .content {
      width: calc(100% - 4px);
      height: calc(100% - 4px);
      background-size: cover;
      background-position: center;
      border-radius: 50%;
      box-shadow: 0 0 30px rgba(0,0,0,0.3);
    }
    
    .cards-container-manager {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 30px;
      max-width: 1400px;
      margin: 40px auto 0;
      padding: 0 20px 30px;
      position: relative;
      z-index: 5;
    }
    
    .cards-container-manager::after {
      content: '';
      position: absolute;
      bottom: -15px;
      left: 10%;
      width: 80%;
      height: 4px;
      background: linear-gradient(90deg, transparent, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000, transparent);
      background-size: 200% 100%;
      border-radius: 4px;
      animation: rainbowLine 3s linear infinite;
    }
    
    .manager-card {
      background: rgba(255, 255, 255, 0.1);
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 25px;
