    .invoice-item {
      background: rgba(255,255,255,0.08);
      padding: 12px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
    }
    
    .group-invoice-item {
      background: rgba(59,130,246,0.2);
      border-left: 3px solid #3b82f6;
    }
    
    .restaurant-invoice {
      background: linear-gradient(135deg, rgba(34,197,94,0.2), rgba(34,197,94,0.05));
