      padding: 30px;
      max-width: 500px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
    }
    
    .image-preview {
      width: 100px;
      height: 100px;
      border-radius: 15px;
      object-fit: cover;
      margin: 10px auto;
      display: block;
      border: 2px solid #22c55e;
    }
    
    .qr-placeholder-box {
      background: rgba(0,0,0,0.5);
      border: 2px dashed #22c55e;
      border-radius: 20px;
      padding: 40px;
      text-align: center;
      margin: 20px 0;
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-position: center 30%;
      background-size: cover;
      filter: brightness(0.85) contrast(1.05);
      transition: transform 0.5s ease;
