                      </div>
                    </div>
                    
                    {/* Card 2: Gestion des groupes */}
                    <div className="manager-card">
                      <div className="card-title"><span>👥</span> Gestion des groupes</div>
                      <div className="input-group">
                        <label>Nom du groupe:</label>
                        <input type="text" value={newGroupName} onChange={(e) => setNewGroupName(e.target.value)} placeholder="Ex: Groupe A" />
                      </div>
                      <button className="btn-primary" onClick={addGroup}>➕ Ajouter un groupe</button>
                      <div className="group-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Groupes ({groups.length})</h4>
