                          <div key={group.id} className="group-item">
                            <span style={{ color: 'white' }}>{group.name}</span>
                            <button className="btn-secondary" style={{ padding: '5px 10px', fontSize: '0.7rem' }}
                              onClick={() => {
                                const start = prompt("Début:");
                                const end = prompt("Fin:");
                                if (start && end) assignTablesToGroup(group.id, parseInt(start), parseInt(end));
                              }}>🪑 Assigner</button>
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* Card 3: Employés */}
                    <div className="manager-card">
                      <div className="card-title"><span>👨‍🍳</span> Employés</div>
                      <div className="input-group">
                        <label>Nom employé:</label>
                        <input type="text" value={newEmployeeName} onChange={(e) => setNewEmployeeName(e.target.value)} placeholder="Ex: Ahmed" />
                      </div>
                      <button className="btn-primary" onClick={addEmployee}>➕ Ajouter</button>
                      <div className="employee-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Employés ({employees.length})</h4>
                        {employees.map(emp => (
                          <div key={emp.id} className="employee-item">
                            <span style={{ color: 'white' }}>{emp.name}</span>
                            <select value={emp.groupId || ""} onChange={(e) => assignEmployeeToGroup(emp.id, parseInt(e.target.value))}
                              style={{ background: 'rgba(34,197,94,0.2)', border: '1px solid #22c55e', borderRadius: '10px', padding: '5px', color: 'white' }}>
                              <option value="">Sans groupe</option>
                              {groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
                            </select>
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* Card 4: Menu */}
                    <div className="manager-card">
                      <div className="card-title"><span>📝</span> Menu</div>
                      <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '15px' }}>
                        <button className="btn-primary" style={{ padding: '8px 12px', fontSize: '0.8rem' }} onClick={() => setShowAddProductModal(true)}>➕ Ajouter</button>
                        <button className="btn-secondary" style={{ padding: '8px 12px', fontSize: '0.8rem' }} onClick={() => setShowDeleteProductModal(true)}>🗑️ Supprimer</button>
                        <button className="btn-secondary" style={{ padding: '8px 12px', fontSize: '0.8rem' }} onClick={() => setShowEditPriceModal(true)}>💰 Prix</button>
                      </div>
                      <div>
                        {menuCategories.slice(0, 2).map(cat => (
                          <div key={cat.id} style={{ marginBottom: '10px' }}>
                            <h5 style={{ color: cat.color, fontSize: '0.9rem' }}>{cat.icon} {cat.name}</h5>
                            <div style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.6)' }}>{cat.products.length} produits</div>
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* Card 5: Restaurant Card */}
                    <div className="manager-card">
                      <div className="card-title"><span>🏪</span> Carte restaurant</div>
                      <div style={{ textAlign: 'center' }}>
                        <img src={restaurantCard.logo} alt="logo" style={{ width: '50px', height: '50px', borderRadius: '50%', marginBottom: '10px' }} />
                        <h4 style={{ color: '#22c55e', fontSize: '1rem' }}>{restaurantCard.name}</h4>
                        <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.7rem' }}>{restaurantCard.location}</p>
                      </div>
                      <button className="btn-primary" style={{ width: '100%', marginTop: '10px' }} onClick={() => setShowEditRestaurantModal(true)}>✏️ Modifier</button>
                    </div>
                    
                    {/* Card 6: Factures */}
                    <div className="manager-card">
                      <div className="card-title"><span>📊</span> Factures</div>
                      <div className="input-group">
                        <select value={filterType} onChange={(e) => setFilterType(e.target.value)} style={{ width: '100%', padding: '8px' }}>
                          <option value="daily">📅 Quotidienne</option>
                          <option value="monthly">📆 Mensuelle</option>
                          <option value="seasonal">🌿 Saisonnière</option>
                        </select>
                      </div>
                      <button className="btn-primary" onClick={toggleInvoices} style={{ width: '100%' }}>
                        {showInvoices ? "🙈 Masquer" : "🔍 Afficher"}
                      </button>
                      {showInvoices && (
                        <div className="invoice-stats" style={{ marginTop: '15px', padding: '15px' }}>
                          <h3 style={{ fontSize: '1.5rem' }}>{getTotalRevenue()} DA</h3>
                          <p style={{ fontSize: '0.7rem' }}>Total revenus</p>
                        </div>
                      )}
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{managerInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {managerInfo.languages.map((lang, i) => (<span key={i} className="skill-tag">{lang}</span>))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* Modals... (same as before) */}
      {showQRPlaceholder && selectedTableForQR && (
        <div className="modal-overlay" onClick={() => setShowQRPlaceholder(false)}>
          <div className="modal-content">
            <h2 style={{ color: 'white', textAlign: 'center' }}>📱 Code QR - Table {selectedTableForQR.number}</h2>
            <div className="qr-placeholder-box">
              <div style={{ fontSize: '4rem' }}>📱</div>
              <p style={{ color: '#22c55e' }}>Placeholder QR Code</p>
            </div>
            <button className="btn-primary" style={{ width: '100%' }} onClick={() => setShowQRPlaceholder(false)}>Fermer</button>
          </div>
        </div>
      )}
      
      {showAddProductModal && (
        <div className="modal-overlay" onClick={() => setShowAddProductModal(false)}>
          <div className="modal-content">
            <h2 style={{ color: 'white' }}>➕ Ajouter produit</h2>
            <div className="input-group"><label>Catégorie:</label><select onChange={(e) => setSelectedCategory(parseInt(e.target.value))}><option value="">Choisir</option>{menuCategories.map(cat => (<option key={cat.id} value={cat.id}>{cat.name}</option>))}</select></div>
            <div className="input-group"><label>Nom:</label><input type="text" value={newProduct.name} onChange={(e) => setNewProduct({...newProduct, name: e.target.value})} /></div>
            <div className="input-group"><label>Prix:</label><input type="number" value={newProduct.price} onChange={(e) => setNewProduct({...newProduct, price: parseFloat(e.target.value)})} /></div>
            <div className="input-group"><label>Image URL:</label><input type="text" value={newProduct.image} onChange={handleProductImageChange} /></div>
            {productImagePreview && <img src={productImagePreview} className="image-preview" alt="preview" />}
            <button className="btn-primary" style={{ width: '100%' }} onClick={addProduct}>💾 Enregistrer</button>
          </div>
        </div>
      )}
      
      {showDeleteProductModal && (
        <div className="modal-overlay" onClick={() => setShowDeleteProductModal(false)}>
          <div className="modal-content">
            <h2 style={{ color: 'white' }}>🗑️ Supprimer produit</h2>
            {menuCategories.map(cat => (<div key={cat.id}><h3 style={{ color: cat.color }}>{cat.name}</h3>{cat.products.map(p => (<div key={p.id} className="product-item"><span>{p.name}</span><button className="btn-danger" onClick={() => deleteProduct(cat.id, p.id)}>Supprimer</button></div>))}</div>))}
          </div>
        </div>
      )}
      
      {showEditPriceModal && (
        <div className="modal-overlay" onClick={() => setShowEditPriceModal(false)}>
          <div className="modal-content">
            <h2 style={{ color: 'white' }}>💰 Modifier prix</h2>
            {menuCategories.map(cat => (<div key={cat.id}><h3 style={{ color: cat.color }}>{cat.name}</h3>{cat.products.map(p => (<div key={p.id} className="product-item"><span>{p.name} ({p.price} DA)</span><button className="btn-secondary" onClick={() => { const newPrice = prompt("Nouveau prix:", p.price); if (newPrice) updateProductPrice(cat.id, p.id, parseFloat(newPrice)); }}>Modifier</button></div>))}</div>))}
          </div>
        </div>
      )}
      
      {showEditRestaurantModal && (
        <div className="modal-overlay" onClick={() => setShowEditRestaurantModal(false)}>
          <div className="modal-content">
            <h2 style={{ color: 'white' }}>✏️ Modifier carte</h2>
            <div className="input-group"><label>Nom:</label><input type="text" value={tempRestaurantCard.name} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, name: e.target.value})} /></div>
            <div className="input-group"><label>Location:</label><input type="text" value={tempRestaurantCard.location} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, location: e.target.value})} /></div>
            <div className="input-group"><label>Description:</label><textarea rows="2" value={tempRestaurantCard.description} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, description: e.target.value})} /></div>
            <div className="input-group"><label>Téléphone:</label><input type="text" value={tempRestaurantCard.phone} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, phone: e.target.value})} /></div>
            <div className="input-group"><label>Email:</label><input type="email" value={tempRestaurantCard.email} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, email: e.target.value})} /></div>
            <div className="input-group"><label>Logo URL:</label><input type="text" value={tempRestaurantCard.logo} onChange={handleRestaurantLogoChange} /></div>
            <div className="input-group"><label>Image URL:</label><input type="text" value={tempRestaurantCard.image} onChange={handleRestaurantImageChange} /></div>
            {restaurantImagePreview && <img src={restaurantImagePreview} className="image-preview" alt="preview" />}
            <button className="btn-primary" style={{ width: '100%' }} onClick={updateRestaurantCard}>💾 Enregistrer</button>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
